local LModel = LModel
------------------------------------------------------------------
---@class ModelGameHelper:LModel
local ModelGameHelper = LxClass("ModelGameHelper",LModel)
------------------------------------------------------------------
function ModelGameHelper:ModelGameHelper()
    self.setting = {}
end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelGameHelper:OnModelInit()
    self:ModelNetMsgRecv(LProtoIds.GameHelperSettingResp, function(pb)
        self:GameHelperSettingResp(pb)
    end)
end

--在协议数据处理完之后需要调用finish
function ModelGameHelper:OnModelRequest()
    self:ModelFinish()
end

--清理工作
--停止计时器之类的
function ModelGameHelper:OnModelClear()

end
--//type 处理类型：1=查看，2=设置  //setting当前分页修改的设置信息
function ModelGameHelper:GameHelperSettingReq(type, setting)
    local pb = LProtoHelper.CreateProto(LProtoIds.GameHelperSettingReq)
    pb.type = type
    if setting then
        local settingInfo = pb.setting:add()
        settingInfo.refId = setting.refId
        settingInfo.parameter1 = setting.parameter1 or 0
        -- settingInfo.parameter2 = setting.parameter2 or 0
        -- settingInfo.parameter3 = setting.parameter3 or 0
        settingInfo.moreInfo = setting.moreInfo or ""
    end
    SendMessage(pb, LProtoIds.GameHelperSettingReq)
end

function ModelGameHelper:GameHelperExecuteReq(refIds)
    local pb = LProtoHelper.CreateProto(LProtoIds.GameHelperExecuteReq)
    for _, v in ipairs(refIds) do
        pb.refId:append(v)
    end
    SendMessage(pb, LProtoIds.GameHelperExecuteReq)
end

function ModelGameHelper:GameHelperStopExecuteReq(type)
    local pb = LProtoHelper.CreateProto(LProtoIds.GameHelperStopExecuteReq)
    pb.type = type
    SendMessage(pb, LProtoIds.GameHelperStopExecuteReq)
end

function ModelGameHelper:GameHelperSettingResp(pb)
    for _, v in ipairs(pb.setting) do
        if not self.setting[v.refId] then
            self.setting[v.refId] = {}
        end
        local data = {
            refId = v.refId,
            parameter1 = v.parameter1,
            -- parameter2 = v.parameter2,
            -- parameter3 = v.parameter3,
            moreInfo = v.moreInfo,
            functionData = v.functionData,
            clienShowData = JSON.decode(v.clienShowData)
        }
        self.setting[v.refId] = data
    end

    FireEvent("GameHelperSettingResp")
end

function ModelGameHelper:GetHelperSpeedList()
    local ref = self:GetModelConfig("AssistantAccelerate")
    return ref
end

function ModelGameHelper:GetHelpSpeedRef(refId)
    local ref = self:GetHelperSpeedList()
    if ref then
        return ref[refId]
    end
end

function ModelGameHelper:SetGameSpeed(speed)
    LPlayerPrefs.SetHelperSpeed(tostring(speed))
    self:RefreshGameSpeed()
end

function ModelGameHelper:ApplySpeed()

    local isSpeed = not self:IsSpeeded()
    self:SetGameSpeedOn(isSpeed)

    self:RefreshGameSpeed()


    local tip = nil
    if isSpeed then
        tip =ccClientText(24211)
    else
        tip =ccClientText(24210)
    end
    GF.ShowMessage(tip)

end

function ModelGameHelper:RefreshGameSpeed()

    if self._GMSpeed then
        gLGame:SetBaseTimeScale(self._GMSpeed)
        return
    end

    local speedValue = self:GetHelperSpeedValue()

    if LOG_INFO_ENABLED then
        print("ModelGameHelper:RefreshGameSpeed() "..speedValue)
    end

    ---童话镇地图用自定义的速度
    local map = GF.GetCurMap()
    if map and map.GetGameTimeScaleBySpeedValue then
        local timeValue = map:GetGameTimeScaleBySpeedValue(speedValue)
        if timeValue then
            gLGame:SetBaseTimeScale(timeValue)
            return
        end
    end

    local ref = self:GetHelpSpeedRef(speedValue)
    if ref then
        gLGame:SetBaseTimeScale(ref.valueBase)
    end

end

--临时关闭加速  特定场景用到  http://192.168.16.2:3002/issues/1071
--临时关闭结束 请调用gModelGameHelper:RefreshGameSpeed()
function ModelGameHelper:TemporaryCloseSpeed()
    local ref = self:GetHelpSpeedRef(1)
    if ref then
        gLGame:SetBaseTimeScale(ref.valueBase)
    end
    print("--------临时关闭加速--------")
end

function ModelGameHelper:GetHelperSpeedValue()
    local speedValue = 1

    local isSpeed = self:IsSpeeded()
    if not isSpeed then
        return speedValue
    end

    if self:GetOnlyBattle() then
        local hasBattleFront = gLFightManager:HasBattleInFront()
        if not hasBattleFront then
            return speedValue
        end
    end

    local forbidSpeedMapList = {
        ["LSleepMap"] = true,
    }

    local map = GF.GetCurMap()
    if map and forbidSpeedMapList[map:GetMapClassName()] then
        return speedValue
    end

    return self:GetGameSpeed()
end

function ModelGameHelper:GetGameSpeed()
    return tonumber(LPlayerPrefs.helperSpeed)  or 1
end

function ModelGameHelper:SetGameSpeedOn(isOn)
    local value = isOn and 1 or 0
    LPlayerPrefs.SetHelperSpeedOn(value)
end

function ModelGameHelper:IsSpeeded()
    local onRecord = tonumber(LPlayerPrefs.helperSpeedOn) or 0
    return onRecord == 1
end

function ModelGameHelper:GetUnLockMaxSpeed()
    local ref = self:GetHelperSpeedList()
    local max = 1
    for k,v in ipairs(ref) do
        local isOpen = gModelFunctionOpen:CheckOpenCondition(v.open)
        if isOpen then
            max = math.max(max,k)
        end
    end

    return max
end

function ModelGameHelper:GMSetGameSpeed(value)

    self._GMSpeed = value

    self:RefreshGameSpeed()
end

function ModelGameHelper:GetOnlyBattle()
    local value = tonumber(LPlayerPrefs.gameHelperTog) == 1
    return value
end

function ModelGameHelper:SetOnlyBattle(value)
    local key = value and 1 or 0
    LPlayerPrefs.SetHelperTog(key)

    self:RefreshGameSpeed()
end

function ModelGameHelper:GetTabList()
    if not self.tabList then
        self.tabList = {}
        for _, v in pairs(GameTable.AssistantTabRef) do
            local data = {
                func = string.split(v.icon, "|"),
                open = v.functionOpenId,
                sort = v.sort,
                name = v.name,
                tabIcon = v.tabIcon,
                id = v.refId
            }
            table.insert(self.tabList, data)
        end
        table.sort(self.tabList, function(a, b)
            return a.sort < b.sort
        end)
    end

    return self.tabList
end

function ModelGameHelper:CheckIsOpen(str)
    local info = string.split(str, "=")
    local type = tonumber(info[1])
    local para = tonumber(info[2])
    local func = gModelFunctionOpen:GetCheckFuns(type)
    return func(para)
end

function ModelGameHelper:GetSettingById(id)
    return self.setting[id] or {}
end

function ModelGameHelper:InitDoList()
    local doList = self:GetDolist()
    local list = self:GetTabList()
    for _, v in ipairs(list) do
        local key = v.id
        if doList[key] == nil then
            self:SetDoList(key, true)
        end
    end
end

function ModelGameHelper:GetDolist()
    local jsonS = LPlayerPrefs.GameHelperDoList
    return JSON.decode(jsonS) or {}
end

function ModelGameHelper:SetDoList(key, b)
    local doList = self:GetDolist()
    doList[key] = b
    local jsonS = JSON.encode(doList)
    LPlayerPrefs.SetGameHelperDoList(jsonS)
    return doList
end

function ModelGameHelper:IsInitDoList()
    local b = self.isInitDoList
    if not self.isInitDoList then
        self.isInitDoList = true
    end
    return b
end

function ModelGameHelper:GetGameHelperErrorStr(error)
    local str = ccServerText(error.code)
    local t = {}
    local args = error.args or {}
    for i,v in ipairs(args) do t["a"..i] = v end
    for i,v in ipairs(args) do t["c"..i] = ccLngText(v) end
    for i,v in ipairs(args) do t["e"..i] = gModelItem:FormatItemListStr(v) end
    return string.gsub(str,"#(%w+)#",t)
end

return ModelGameHelper